import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useParams, useNavigate, Link } from "react-router-dom";

function ProductDetails()
{

    const navigate = useNavigate();
    const { slug } = useParams(); // Get the 'slug' from the URL
    const [loading, setLoading] = useState(true);
    const [products, setProduct] = useState([]);
    const [category, setCategory] = useState([]);

    useEffect(() =>
    {
        let isMounted = true;

        const category_slug = props.match.params.category;
        const product_slug = props.match.params.product;
        axios.get(`/api/fetchProducts/${category_slug}/${product_slug}`).then(res =>
        {
            if (isMounted)
            {
                if (res.data.status === 200)
                {
                    setProduct(res.data.product);
                    setCategory(res.data.category);
                    setLoading(false);
                }
                else if (res.data.status === 404)
                {
                    // Use navigate for redirection
                    navigate('/collections');
                    Swal.fire("Warning", res.data.message, "error");
                }
            }
        });

        return () =>
        {
            isMounted = false;
        };
    }, [props.match.params.category, props.match.params.product, navigate]);


    return (
        <div>
            <div classname="py-3 bg-warning">
                <div classname="container">
                    <h6>Collections / Category / Product</h6>
                </div>
            </div>

            <div className="py-3">
                <div className="container">
                    <div className="row">
                        <h4>Product Detail</h4>
                    </div>
                </div>
            </div>
        </div>
    )
} export default ProductDetails;
